"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[7665],{2348(e,a,r){r.r(a),r.d(a,{assets:()=>o,contentTitle:()=>t,default:()=>m,frontMatter:()=>l,metadata:()=>n,toc:()=>d});const n=JSON.parse('{"id":"features-usage/shortcodes","title":"shortcodes","description":"[rentivavehiclesgrid columns=\\"4\\" postsperpage=\\"12\\" show_filters=\\"0\\"]","source":"@site/docs/03-features-usage/shortcodes.md","sourceDirName":"03-features-usage","slug":"/features-usage/shortcodes","permalink":"/mhm-rentiva-docs/en/docs/next/features-usage/shortcodes","draft":false,"unlisted":false,"editUrl":"https://github.com/MaxHandMade/mhm-rentiva/tree/main/website/docs/03-features-usage/shortcodes.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Raporlar","permalink":"/mhm-rentiva-docs/en/docs/next/features-usage/reports"},"next":{"title":"vehicle-settings","permalink":"/mhm-rentiva-docs/en/docs/next/features-usage/vehicle-settings"}}');var i=r(4848),s=r(8453);const l={},t=void 0,o={},d=[];function c(e){const a={code:"code",p:"p",pre:"pre",...(0,s.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(a.pre,{children:(0,i.jsx)(a.code,{children:"---\nid: shortcodes\ntitle: K\u0131sa Kodlar (Shortcodes)\nsidebar_label: K\u0131sa Kodlar\nslug: /features-usage/shortcodes\n---\n\n# Shortcodes (K\u0131sa Kodlar)\n\nMHM Rentiva, sitenizin \xe7e\u015fitli yerlerinde ara\xe7 listeleri, formlar ve di\u011fer \xf6zellikleri g\xf6r\xfcnt\xfclemek i\xe7in kapsaml\u0131 bir k\u0131sa kod seti sunar. A\u015fa\u011f\u0131da mevcut t\xfcm k\u0131sa kodlar\u0131n bir listesi ve kullan\u0131m detaylar\u0131 bulunmaktad\u0131r.\n\n## Ara\xe7 Listeleme ve G\xf6r\xfcn\xfcm\n\n### 1. Ara\xe7 Izgaras\u0131 (Grid)\nAra\xe7lar\u0131 \u0131zgara (grid) d\xfczeninde listeler.\n\n**K\u0131sa Kod:** `[rentiva_vehicles_grid]`\n\n**Parametreler:**\n*   `posts_per_page`: Sayfada g\xf6sterilecek ara\xe7 say\u0131s\u0131. Varsay\u0131lan: `9`.\n*   `orderby`: S\u0131ralama kriteri (`date`, `title`, `price`, `rand`). Varsay\u0131lan: `date`.\n*   `order`: S\u0131ralama y\xf6n\xfc (`ASC`, `DESC`). Varsay\u0131lan: `DESC`.\n*   `columns`: S\xfctun say\u0131s\u0131 (masa\xfcst\xfc i\xe7in). Varsay\u0131lan: `3`.\n*   `show_filters`: Filtreleri g\xf6ster (`1` veya `0`). Varsay\u0131lan: `1`.\n*   `category`: Belirli bir kategorideki ara\xe7lar\u0131 filtrelemek i\xe7in kategori slug'\u0131.\n\n**\xd6rnek:**\n"})}),"\n",(0,i.jsx)(a.p,{children:'[rentiva_vehicles_grid columns="4" posts_per_page="12" show_filters="0"]'}),"\n",(0,i.jsx)(a.pre,{children:(0,i.jsx)(a.code,{children:"\n### 2. Ara\xe7 Listesi (List)\nAra\xe7lar\u0131 liste g\xf6r\xfcn\xfcm\xfcnde g\xf6sterir.\n\n**K\u0131sa Kod:** `[rentiva_vehicles_list]`\n\n**Parametreler:**\n*   `posts_per_page`: Sayfada g\xf6sterilecek ara\xe7 say\u0131s\u0131. Varsay\u0131lan: `10`.\n*   `orderby`: S\u0131ralama kriteri. Varsay\u0131lan: `date`.\n*   `order`: S\u0131ralama y\xf6n\xfc. Varsay\u0131lan: `DESC`.\n*   `show_filters`: Filtreleri g\xf6ster. Varsay\u0131lan: `1`.\n\n**\xd6rnek:**\n"})}),"\n",(0,i.jsx)(a.p,{children:'[rentiva_vehicles_list posts_per_page="5"]'}),"\n",(0,i.jsx)(a.pre,{children:(0,i.jsx)(a.code,{children:"\n### 3. Arama Sonu\xe7lar\u0131\nAra\xe7 arama sonu\xe7lar\u0131n\u0131 listeler. Arama formu taraf\u0131ndan y\xf6nlendirilen sayfada kullan\u0131l\u0131r.\n\n**K\u0131sa Kod:** `[rentiva_search_results]`\n\n**Parametreler:**\nBu k\u0131sa kod genellikle parametre almaz, URL \xfczerinden gelen arama sorgular\u0131n\u0131 (`GET` parametreleri) i\u015fler.\n\n### 4. Ara\xe7 Detaylar\u0131\nTek bir arac\u0131n detaylar\u0131n\u0131 g\xf6sterir. Genellikle `single-vehicle.php` \u015fablonu i\xe7inde veya \xf6zel bir sayfada belirli bir arac\u0131 g\xf6stermek i\xe7in kullan\u0131l\u0131r.\n\n**K\u0131sa Kod:** `[rentiva_vehicle_details]`\n\n**Parametreler:**\n*   `vehicle_id`: G\xf6sterilecek arac\u0131n ID'si. Belirtilmezse mevcut sayfan\u0131n veya d\xf6ng\xfcn\xfcn ID'sini kullan\u0131r.\n*   `show_gallery`: Galeriyi g\xf6ster (`1` veya `0`). Varsay\u0131lan: `1`.\n*   `show_features`: \xd6zellikleri g\xf6ster. Varsay\u0131lan: `1`.\n*   `show_pricing`: Fiyat\u0131 g\xf6ster. Varsay\u0131lan: `1`.\n*   `show_booking`: Rezervasyon formunu/butonunu g\xf6ster. Varsay\u0131lan: `1`.\n*   `show_calendar`: M\xfcsaitlik takvimini g\xf6ster. Varsay\u0131lan: `1`.\n\n**\xd6rnek:**\n"})}),"\n",(0,i.jsx)(a.p,{children:'[rentiva_vehicle_details vehicle_id="123"]'}),"\n",(0,i.jsx)(a.pre,{children:(0,i.jsx)(a.code,{children:"\n### 5. Ara\xe7 Kar\u015f\u0131la\u015ft\u0131rma\nSe\xe7ilen ara\xe7lar\u0131 kar\u015f\u0131la\u015ft\u0131rmal\u0131 bir tablo veya kart g\xf6r\xfcn\xfcm\xfcnde sunar.\n\n**K\u0131sa Kod:** `[rentiva_vehicle_comparison]`\n\n**Parametreler:**\n*   `vehicle_ids`: Kar\u015f\u0131la\u015ft\u0131r\u0131lacak ara\xe7lar\u0131n virg\xfclle ayr\u0131lm\u0131\u015f ID'leri.\n*   `show_features`: G\xf6sterilecek \xf6zellikler (`all`, `basic`, `detailed`). Varsay\u0131lan: `all`.\n*   `max_vehicles`: Maksimum kar\u015f\u0131la\u015ft\u0131r\u0131labilecek ara\xe7 say\u0131s\u0131. Varsay\u0131lan: `4`.\n*   `layout`: G\xf6r\xfcn\xfcm d\xfczeni (`table`, `cards`). Varsay\u0131lan: `table`.\n\n**\xd6rnek:**\n"})}),"\n",(0,i.jsx)(a.p,{children:'[rentiva_vehicle_comparison vehicle_ids="101,102,103" layout="table"]'}),"\n",(0,i.jsx)(a.pre,{children:(0,i.jsx)(a.code,{children:"\n## Rezervasyon ve M\xfcsaitlik\n\n### 6. Rezervasyon Formu\nGeli\u015fmi\u015f rezervasyon formunu g\xf6r\xfcnt\xfcler.\n\n**K\u0131sa Kod:** `[rentiva_booking_form]`\n\n**Parametreler:**\n*   `vehicle_id`: Belirli bir ara\xe7 i\xe7in form olu\u015fturur.\n*   `show_vehicle_selector`: Ara\xe7 se\xe7im alan\u0131n\u0131 g\xf6ster (`1` veya `0`). Varsay\u0131lan: `1`.\n*   `show_addons`: Ek hizmetleri g\xf6ster. Varsay\u0131lan: `1`.\n*   `enable_deposit`: Depozito sistemini aktif et. Varsay\u0131lan: `1`.\n*   `redirect_url`: Ba\u015far\u0131l\u0131 i\u015flem sonras\u0131 y\xf6nlendirilecek URL.\n\n**\xd6rnek:**\n"})}),"\n",(0,i.jsx)(a.p,{children:'[rentiva_booking_form vehicle_id="55" show_vehicle_selector="0"]'}),"\n",(0,i.jsx)(a.pre,{children:(0,i.jsx)(a.code,{children:"\n### 7. M\xfcsaitlik Takvimi\nBir arac\u0131n m\xfcsaitlik durumunu takvim \xfczerinde g\xf6sterir.\n\n**K\u0131sa Kod:** `[rentiva_availability_calendar]`\n\n**Parametreler:**\n*   `vehicle_id`: Takvimi g\xf6sterilecek ara\xe7 ID'si.\n*   `months_to_show`: G\xf6sterilecek ay say\u0131s\u0131. Varsay\u0131lan: `1` (Filtre ile `3` olabilir).\n*   `show_pricing`: G\xfcnl\xfck fiyatlar\u0131 g\xf6ster. Varsay\u0131lan: `1`.\n*   `theme`: Takvim temas\u0131 (`default`, `compact`).\n\n**\xd6rnek:**\n"})}),"\n",(0,i.jsx)(a.p,{children:'[rentiva_availability_calendar vehicle_id="123" months_to_show="3"]'}),"\n",(0,i.jsx)(a.pre,{children:(0,i.jsx)(a.code,{children:"\n### 8. Rezervasyon Onay\u0131\nRezervasyon tamamland\u0131ktan sonra g\xf6sterilen onay sayfas\u0131 i\xe7eri\u011fidir.\n\n**K\u0131sa Kod:** `[rentiva_booking_confirmation]`\n\n**Parametreler:**\n*   `booking_id`: Onay detaylar\u0131 g\xf6sterilecek rezervasyon ID'si (URL parametresi olarak da al\u0131nabilir).\n\n\n\n## Di\u011fer \u0130\u015flevler\n\n### 10. \u0130leti\u015fim Formlar\u0131\n\xc7e\u015fitli ama\xe7lar i\xe7in (genel, rezervasyon, destek) ileti\u015fim formlar\u0131 olu\u015fturur.\n\n**K\u0131sa Kod:** `[rentiva_contact]`\n\n**Parametreler:**\n*   `type`: Form tipi (`general`, `booking`, `support`, `feedback`). Varsay\u0131lan: `general`.\n\n**\xd6rnek:**\n"})}),"\n",(0,i.jsx)(a.p,{children:'[rentiva_contact type="support"]'}),"\n",(0,i.jsx)(a.pre,{children:(0,i.jsx)(a.code,{children:"\n### 11. M\xfc\u015fteri Yorumlar\u0131 (Testimonials)\nM\xfc\u015fteri yorumlar\u0131n\u0131 listeler.\n\n**K\u0131sa Kod:** `[rentiva_testimonials]`\n\n**Parametreler:**\n*   `limit`: G\xf6sterilecek yorum say\u0131s\u0131. Varsay\u0131lan: `5`.\n*   `rating`: Belirli bir puana sahip yorumlar\u0131 filtreler (\xd6rn: `5` y\u0131ld\u0131zl\u0131lar).\n*   `vehicle_id`: Sadece belirli bir araca ait yorumlar\u0131 g\xf6sterir.\n*   `layout`: G\xf6r\xfcn\xfcm d\xfczeni (`grid`, `slider`, `list`). Varsay\u0131lan: `grid`.\n*   `columns`: Grid g\xf6r\xfcn\xfcm\xfc i\xe7in s\xfctun say\u0131s\u0131 (3 veya 4). Varsay\u0131lan: `3`.\n*   `show_rating`: Y\u0131ld\u0131z puanlamas\u0131n\u0131 g\xf6ster (`1` veya `0`). Varsay\u0131lan: `1`.\n*   `show_date`: Yorum tarihini g\xf6ster (`1` veya `0`). Varsay\u0131lan: `1`.\n*   `show_vehicle`: Ara\xe7 ismini g\xf6ster (`1` veya `0`). Varsay\u0131lan: `1`.\n*   `show_customer`: M\xfc\u015fteri ismini/ba\u015f harflerini g\xf6ster (`1` veya `0`). Varsay\u0131lan: `1`.\n*   `auto_rotate`: Slider i\xe7in otomatik ge\xe7i\u015f s\xfcresi (ms cinsinden, 0 = kapal\u0131). Varsay\u0131lan: `0`.\n\n**\xd6rnek:**\n"})}),"\n",(0,i.jsx)(a.p,{children:'[rentiva_testimonials limit="6" layout="slider" show_rating="1" auto_rotate="5000"]'}),"\n",(0,i.jsx)(a.pre,{children:(0,i.jsx)(a.code,{children:"\n### 12. Ara\xe7 Puanlama Formu\nKullan\u0131c\u0131lar\u0131n ara\xe7lara puan vermesini ve yorum yapmas\u0131n\u0131 sa\u011flayan geli\u015fmi\u015f form. Kullan\u0131c\u0131n\u0131n rezervasyon ge\xe7mi\u015fini kontrol eder ve sadece kiralama yapm\u0131\u015f kullan\u0131c\u0131lara (veya ayarlara g\xf6re herkese) yorum izni verir.\n\n**K\u0131sa Kod:** `[rentiva_vehicle_rating_form]`\n\n**Parametreler:**\n*   `vehicle_id`: Puanlanacak ara\xe7 ID'si. Belirtilmezse mevcut sayfan\u0131n ID'si kullan\u0131l\u0131r.\n*   `show_rating_display`: Mevcut ortalama puan\u0131 ve y\u0131ld\u0131zlar\u0131 g\xf6ster (`1` veya `0`). Varsay\u0131lan: `1`.\n*   `show_form`: Yorum g\xf6nderme formunu g\xf6ster (`1` veya `0`). Varsay\u0131lan: `1`.\n*   `show_ratings_list`: Alt k\u0131s\u0131mda yap\u0131lan yorumlar\u0131 listele (`1` veya `0`). Varsay\u0131lan: `1`.\n\n**\xd6rnek:**\n"})}),"\n",(0,i.jsx)(a.p,{children:'[rentiva_vehicle_rating_form show_ratings_list="1"]'}),"\n",(0,i.jsx)(a.pre,{children:(0,i.jsx)(a.code,{children:"\n### 13. M\xfc\u015fteri Mesajlar\u0131\nM\xfc\u015fterilerin y\xf6netici ile ileti\u015fime ge\xe7ebilece\u011fi ve mesaj ge\xe7mi\u015fini g\xf6r\xfcnt\xfcleyebilece\u011fi mesajla\u015fma merkezi. Sadece giri\u015f yapm\u0131\u015f kullan\u0131c\u0131lar g\xf6rebilir.\n\n**K\u0131sa Kod:** `[rentiva_messages]`\nSadece m\xfc\u015fteri mesajla\u015fma merkezini g\xf6sterir.\n"})})]})}function m(e={}){const{wrapper:a}={...(0,s.R)(),...e.components};return a?(0,i.jsx)(a,{...e,children:(0,i.jsx)(c,{...e})}):c(e)}},8453(e,a,r){r.d(a,{R:()=>l,x:()=>t});var n=r(6540);const i={},s=n.createContext(i);function l(e){const a=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(a):{...a,...e}},[a,e])}function t(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:l(e.components),n.createElement(s.Provider,{value:a},e.children)}}}]);